import React, { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import axios from "axios";

const EditDrug = () => {
    const { id } = useParams(); // Lấy ID từ URL
    const [drug, setDrug] = useState({
        code: "",
        name: "",
        typeId: "",
        price: "",
        unit: "",
        description: "",
    });

    // Gọi API lấy dữ liệu thuốc cũ
    useEffect(() => {
        axios
            .get(`http://localhost:3000/medicines/${id}`)
            .then((response) => {
                setDrug(response.data); // Gán dữ liệu vào state
            })
            .catch((error) => {
                console.error("Lỗi khi lấy dữ liệu thuốc:", error);
            });
    }, [id]);

    // Hàm xử lý thay đổi input
    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    return (
        <div>
            <h2>Chỉnh sửa thuốc</h2>
            <form>
                <label>Mã thuốc:</label>
                <input name="code" value={drug.code} onChange={handleChange} />

                <label>Tên thuốc:</label>
                <input name="name" value={drug.name} onChange={handleChange} />

                <label>ID loại thuốc:</label>
                <input name="typeId" value={drug.typeId} onChange={handleChange} />

                <label>Giá:</label>
                <input name="price" value={drug.price} onChange={handleChange} />

                <label>Đơn vị:</label>
                <input name="unit" value={drug.unit} onChange={handleChange} />

                <label>Mô tả:</label>
                <textarea name="description" value={drug.description} onChange={handleChange} />

                <button type="submit">Lưu lại</button>
            </form>
        </div>
    );
};

export default EditDrug;
